import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import './CustomerDashboard.css';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

const CustomerTransactions = () => {
  const [transactions, setTransactions] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchTransactions();
  }, []);

  const fetchTransactions = async () => {
    try {
      const response = await axios.get(`${API_URL}/transactions`);
      setTransactions(response.data.data || response.data);
    } catch (error) {
      console.error('Error fetching transactions:', error);
    } finally {
      setLoading(false);
    }
  };

  const formatDate = (dateString) => {
    return new Date(dateString).toLocaleDateString('en-US', {
      month: 'short',
      day: 'numeric',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  if (loading) {
    return (
      <div className="main-content" style={{ marginLeft: 0, padding: '2rem' }}>
        <div className="loading">Loading...</div>
      </div>
    );
  }

  return (
    <div className="main-content" style={{ marginLeft: 0, padding: '2rem' }}>
      <div style={{ maxWidth: '1200px', margin: '0 auto' }}>
        <h1 style={{ fontSize: '1.75rem', fontWeight: 600, marginBottom: '2rem', color: '#212529' }}>
          My Transactions
        </h1>
        
        {transactions.length === 0 ? (
          <div style={{ background: 'white', border: '1px solid #dee2e6', borderRadius: '8px', padding: '3rem', textAlign: 'center', color: '#6c757d' }}>
            No transactions found.
          </div>
        ) : (
          <div style={{ background: 'white', border: '1px solid #dee2e6', borderRadius: '8px', overflow: 'hidden' }}>
            <div style={{ overflowX: 'auto' }}>
              <table style={{ width: '100%', borderCollapse: 'collapse', minWidth: '800px' }}>
                <thead>
                  <tr style={{ background: '#f8f9fa', borderBottom: '1px solid #dee2e6' }}>
                    <th style={{ padding: '1rem', textAlign: 'left', fontSize: '0.85rem', fontWeight: 600, color: '#495057' }}>Date</th>
                    <th style={{ padding: '1rem', textAlign: 'left', fontSize: '0.85rem', fontWeight: 600, color: '#495057' }}>Rice Type</th>
                    <th style={{ padding: '1rem', textAlign: 'left', fontSize: '0.85rem', fontWeight: 600, color: '#495057' }}>Quantity</th>
                    <th style={{ padding: '1rem', textAlign: 'left', fontSize: '0.85rem', fontWeight: 600, color: '#495057' }}>Amount</th>
                    <th style={{ padding: '1rem', textAlign: 'left', fontSize: '0.85rem', fontWeight: 600, color: '#495057' }}>Status</th>
                    <th style={{ padding: '1rem', textAlign: 'left', fontSize: '0.85rem', fontWeight: 600, color: '#495057' }}>Action</th>
                  </tr>
                </thead>
                <tbody>
                  {transactions.map((transaction) => (
                    <tr key={transaction._id} style={{ borderBottom: '1px solid #dee2e6' }}>
                      <td style={{ padding: '1rem', fontSize: '0.95rem' }}>{formatDate(transaction.createdAt)}</td>
                      <td style={{ padding: '1rem', fontSize: '0.95rem' }}>{transaction.riceType}</td>
                      <td style={{ padding: '1rem', fontSize: '0.95rem' }}>{transaction.quantityKg} kg</td>
                      <td style={{ padding: '1rem', fontSize: '0.95rem' }}>₱{transaction.amountPaid}</td>
                      <td style={{ padding: '1rem' }}>
                        <span style={{
                          padding: '0.25rem 0.5rem',
                          background: '#e9ecef',
                          borderRadius: '4px',
                          fontSize: '0.85rem',
                          color: '#495057'
                        }}>
                          {transaction.status}
                        </span>
                      </td>
                      <td style={{ padding: '1rem' }}>
                        <Link 
                          to={`/customer/rate/${transaction.transactionId}`}
                          style={{
                            color: '#212529',
                            textDecoration: 'none',
                            fontSize: '0.95rem'
                          }}
                        >
                          Rate →
                        </Link>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default CustomerTransactions;
